const canvas = document.getElementById('particles');
if (canvas) {
    const ctx = canvas.getContext('2d');
    let w, h;
    let particles = [];
    let skullStructure = [];
    let collisionMap = []; 
    let scanWidth = 250; 
    let scanHeight = 0;
    let imageObj = new Image();


    const MY_BASE64_IMAGE = "data:image/png;base64,"; 
    
    
    imageObj.src = MY_BASE64_IMAGE;

    imageObj.onload = function() {
        const offCanvas = document.createElement('canvas');
        const offCtx = offCanvas.getContext('2d');
        const ratio = imageObj.height / imageObj.width;
        scanHeight = Math.floor(scanWidth * ratio);
        
        offCanvas.width = scanWidth;
        offCanvas.height = scanHeight;
        offCtx.drawImage(imageObj, 0, 0, scanWidth, scanHeight);
        
        const imageData = offCtx.getImageData(0, 0, scanWidth, scanHeight).data;
        const minDist = 4; 

        for (let y = 0; y < scanHeight; y++) {
            for (let x = 0; x < scanWidth; x++) {
                const index = (y * scanWidth + x) * 4;
                const brightness = (imageData[index] + imageData[index + 1] + imageData[index + 2]) / 3;
                const alpha = imageData[index + 3];

                const isBlack = (brightness < 110 && alpha > 50);
                collisionMap[y * scanWidth + x] = isBlack;

                if (isBlack) {
                    const tooClose = skullStructure.some(p => Math.hypot(p.origX - x, p.origY - y) < minDist);
                    if (!tooClose) {
                        skullStructure.push({
                            x: (x / scanWidth) * 2 - 1,
                            y: (y / scanHeight) * 2 * ratio - ratio,
                            origX: x,
                            origY: y
                        });
                    }
                }
            }
        }
        init();
        animate();
    };

    // ==========================================
    // 3. CLASSE PARTICULE (STABLE)
    // ==========================================
    class Particle {
        constructor() {
            this.reset(true);
        }

        getScale() {
            const ratio = imageObj.height / imageObj.width;
            return Math.min((w / 2) * 0.8, (h / (2 * ratio)) * 0.8);
        }

        reset(isFirstInit = false) {
            let point;
            if (isFirstInit || !this.baseX) {
                point = skullStructure[Math.floor(Math.random() * skullStructure.length)];
            } else {
                const nearby = skullStructure.filter(p => {
                    const px = (w / 2) + (p.x * this.getScale());
                    const py = (h / 2) + (p.y * this.getScale());
                    return Math.hypot(px - this.baseX, py - this.baseY) < 40;
                });
                point = nearby.length > 0 ? nearby[Math.floor(Math.random() * nearby.length)] : skullStructure[Math.floor(Math.random() * skullStructure.length)];
            }

            const finalScale = this.getScale();
            this.baseX = (w / 2) + (point.x * finalScale);
            this.baseY = (h / 2) + (point.y * finalScale);

            if (isFirstInit) {
                this.x = this.baseX;
                this.y = this.baseY;
            }

            this.vx = (Math.random() - 0.5) * 0.15;
            this.vy = (Math.random() - 0.5) * 0.15;
            this.life = 0;
            this.maxLife = 300 + Math.random() * 300;
        }

        update() {
            // Mouvement flottant très léger autour du point d'ancrage
            this.x += this.vx;
            this.y += this.vy;
            this.life++;

            // Contrainte de distance (mouvement de respiration)
            const distToBase = Math.hypot(this.x - this.baseX, this.y - this.baseY);
            if (distToBase > 10) {
                this.vx *= -1;
                this.vy *= -1;
            }

            if (this.life >= this.maxLife) this.reset();
        }
    }

    // ==========================================
    // 4. DESSIN DU RÉSEAU (GLOW & COULEUR)
    // ==========================================
    function drawLines() {
        const maxDist = 80; 
        const ratio = imageObj.height / imageObj.width;
        const finalScale = Math.min((w / 2) * 0.8, (h / (2 * ratio)) * 0.8);

        ctx.lineWidth = 0.6;

        for (let i = 0; i < particles.length; i++) {
            for (let j = i + 1; j < particles.length; j++) {
                const p1 = particles[i];
                const p2 = particles[j];
                const d2 = Math.pow(p1.x - p2.x, 2) + Math.pow(p1.y - p2.y, 2);

                if (d2 < maxDist * maxDist) {
                    const midX = (p1.x + p2.x) / 2;
                    const midY = (p1.y + p2.y) / 2;
                    const imgX = Math.floor(((midX - w / 2) / finalScale + 1) / 2 * scanWidth);
                    const imgY = Math.floor(((midY - h / 2) / finalScale + ratio) / (2 * ratio) * scanHeight);
                    
                    if (collisionMap[imgY * scanWidth + imgX]) {
                        const dist = Math.sqrt(d2);
                        const lifeAlpha = Math.sin((p1.life / p1.maxLife) * Math.PI);
                        const opacity = (1 - (dist / maxDist)) * lifeAlpha;

                        // On reste sur un blanc chaud très élégant
                        const hue = 35; // Teinte crème/or
                        const saturation = 15; 
                        
                        ctx.strokeStyle = `hsla(${hue}, ${saturation}%, 95%, ${opacity * 0.5})`;
                        
                        ctx.beginPath();
                        ctx.moveTo(p1.x, p1.y);
                        ctx.lineTo(p2.x, p2.y);
                        ctx.stroke();
                    }
                }
            }
        }
        ctx.shadowBlur = 0;
    }

    // ==========================================
    // 5. INITIALISATION ET BOUCLE
    // ==========================================
    function init() {
        w = canvas.width = window.innerWidth;
        h = canvas.height = window.innerHeight;
        particles = Array.from({ length: 700 }, () => new Particle());
    }

    function animate() {
        ctx.clearRect(0, 0, w, h);
        
        for (let p of particles) p.update();
        drawLines();
        
        ctx.fillStyle = "#ffe395";
        for (let p of particles) {
            ctx.beginPath();
            ctx.arc(p.x, p.y, 1, 0, Math.PI * 2);
            ctx.fill();
        }
        requestAnimationFrame(animate);
    }

    window.addEventListener('resize', init);
}